#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int offset = 0;
        for (int i = 0; i < M; i++) {
            char query;
            int d;
            scanf(" %c %d", &query, &d);
            if (query == 'C') {
                offset = (offset + d) % N;
            } else if (query == 'A') {
                offset = (offset - d + N) % N;
            } else {
                printf("%d\n", A[(offset + d - 1) % N]);
            }
        }
    }
    return 0;
}

