import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int offset = 0;
            for (int i = 0; i < M; i++) {
                char query = sc.next().charAt(0);
                int d = sc.nextInt();
                if (query == 'C') {
                    offset = (offset + d) % N;
                } else if (query == 'A') {
                    offset = (offset - d + N) % N;
                } else {
                    System.out.println(A[(offset + d - 1) % N]);
                }
            }
        }
    }
}

